type State = { kind: 'ready' } | { kind: 'failed' };
export function label(state: State) {
  switch (state.kind) {
    case 'ready':
      return 'Ready';
    case 'failed':
      return 'Failed';
    default: {
      const _exhaustive: never = state;
      return _exhaustive;
    }
  }
}
